function scrollToChips(){
  document.querySelector('.chips-grid').scrollIntoView({behavior:'smooth',block:'center'});
}

function getHistory(){
  try{return JSON.parse(localStorage.getItem(HISTORY_KEY)||'[]');}
  catch{return[];}
}

function saveHistory(){
  if(!_lastResult)return;
  const arr=getHistory();
  arr.unshift({..._lastResult,ts:new Date().toISOString()});
  localStorage.setItem(HISTORY_KEY,JSON.stringify(arr.slice(0,HISTORY_MAX)));
}

function deleteHistory(i){
  const arr=getHistory();
  arr.splice(i,1);
  localStorage.setItem(HISTORY_KEY,JSON.stringify(arr));
  renderHistory();
}

function clearAllHistory(){
  if(!confirm('すべての履歴を削除しますか？'))return;
  localStorage.removeItem(HISTORY_KEY);
  renderHistory();
}

function renderHistory(){
  const arr=getHistory();
  const el=ge('history-list');
  if(!arr.length){
    el.innerHTML='<div class="history-empty">保存された履歴はありません。<br>「結果を共有」ボタンで保存できます。</div>';
    return;
  }
  el.innerHTML=arr.map((h,i)=>{
    const dt=new Date(h.ts);
    const fmt=`${dt.getMonth()+1}/${dt.getDate()} ${String(dt.getHours()).padStart(2,'0')}:${String(dt.getMinutes()).padStart(2,'0')}`;
    const part=CL_MAT[h.part]?CL_MAT[h.part].name:h.part;
    const mu=MU_MAP[h.mu]?MU_MAP[h.mu].label:h.mu;
    return `<div class="history-item">
      <div class="history-item-body">
        <div><span class="history-torque">${h.torque}</span><span class="history-torque-unit"> N·m</span></div>
        <div class="history-params">M${h.d} / ${h.grade} / ${part} / ${mu}</div>
        <div class="history-ts">${fmt} · ${h.range} N·m</div>
      </div>
      <button class="history-del" onclick="deleteHistory(${i})">削除</button>
    </div>`;
  }).join('');
}

function openHistory(){
  ge('history-modal').style.display='flex';
  renderHistory();
}

function closeHistory(){
  ge('history-modal').style.display='none';
}

function saveAndShare(){
  saveHistory();
  const t=ge('res-torque').textContent;
  const r=ge('res-range').textContent;
  const d=gv('diam'),g=gv('grade'),p=CL_MAT[gv('part_mat')].name,m=MU_MAP[gv('mu')].label;
